#!/usr/bin/env bun
// @bun
import{join}from"path";import{homedir}from"os";import{existsSync,mkdirSync,readFileSync,writeFileSync,chmodSync,renameSync,unlinkSync}from"fs";function stateDir(){return join(homedir(),".codex","fusengine","sessions")}var SID_RE=/^[a-zA-Z0-9_-]{1,128}$/;function sanitizeSessionId(sid){let s=String(sid??"").trim();if(!SID_RE.test(s))throw Error(`Invalid session id: ${JSON.stringify(s)}`);return s}function getStatePath(sid){return join(stateDir(),`session-${sanitizeSessionId(sid)}.json`)}function loadSessionState(sid){let path=getStatePath(sid);if(!existsSync(path))return{};try{let data=JSON.parse(readFileSync(path,"utf-8"));return data&&typeof data==="object"&&!Array.isArray(data)?data:{}}catch{return{}}}var AGENT_TTL_MS=1800000,REQUIRED=["explore-codebase","research-expert"];function safeState(sid){try{return loadSessionState(sid)}catch{return{}}}function fresh(e,now){let t=Date.parse(String(e.timestamp??""));return!Number.isNaN(t)&&now-t<=AGENT_TTL_MS}function checkRequiredAgents(sid){let agents=safeState(sid).agents??[],now=Date.now(),found=new Set;for(let i=agents.length-1;i>=0;i--){let e=agents[i];if(!e||typeof e!=="object"||!fresh(e,now))continue;if((e.quality??"insufficient")!=="sufficient")continue;for(let req of REQUIRED)if((e.type??"").includes(req))found.add(req)}let missing=REQUIRED.filter((r)=>!found.has(r));return{satisfied:missing.length===0,missing}}function checkBrainstormDone(sid){let state=safeState(sid);if(!state.brainstorming_required)return!0;let agents=state.agents??[],now=Date.now();for(let i=agents.length-1;i>=0;i--){let e=agents[i];if(!e||typeof e!=="object"||!fresh(e,now))continue;if((e.type??"").includes("brainstorming"))return(e.quality??"")==="sufficient"}return!1}var CODE_EXT=/\.(ts|tsx|js|jsx|py|go|rs|java|php|cpp|c|rb|swift|kt|dart|vue|svelte|astro)$/,EXEMPT=[/\.codex-plugin\//,/CHANGELOG\.md$/,/marketplace\.json$/,/\/\.codex\/(apex|memory|logs|fusengine)\//,/\/\.codex\/(apex|memory|fusengine)\//];function*filesIn(tool,ti){if(tool==="apply_patch")for(let line of String(ti.command??ti.input??"").split(`
`)){let m=line.match(/^\*\*\*\s+(Add|Update) File:\s+(.+)$/);if(m)yield[m[2].trim(),m[1]==="Add"]}else{let fp=ti.file_path??"";if(fp)yield[fp,tool!=="Edit"]}}function deny(reason){console.log(JSON.stringify({hookSpecificOutput:{hookEventName:"PreToolUse",permissionDecision:"deny",permissionDecisionReason:reason},systemMessage:`require-apex-agents: ${reason.split(`
`)[0].slice(0,180)}`})),process.exit(0)}var data;try{data=JSON.parse(await Bun.stdin.text())}catch{process.exit(0)}var tool=data.tool_name??"",sid=data.session_id||"unknown",isSub=Boolean(data.agent_id);for(let[fp,isNew]of filesIn(tool,data.tool_input??{})){if(!CODE_EXT.test(fp)||EXEMPT.some((p)=>p.test(fp)))continue;if(isNew&&!isSub&&!checkBrainstormDone(sid))deny("BLOCKED: Brainstorming required for new feature/creation task. Launch brainstorming agent BEFORE writing code.");let{satisfied,missing}=checkRequiredAgents(sid);if(satisfied)continue;let missingStr=missing.join(" + ");if(isSub){let hints=[];for(let m of missing){if(m.includes("explore"))hints.push("Glob/Grep (codebase exploration)");if(m.includes("research"))hints.push("Context7/Exa/WebSearch (research)")}deny(`BLOCKED: APEX workflow required (3min TTL). Missing: ${missingStr}. Use ${hints.join(" and ")} BEFORE editing code.`)}else deny(`BLOCKED: APEX workflow required (3min TTL). Missing agents: ${missingStr}. Launch BOTH explore-codebase AND research-expert BEFORE editing code.`)}process.exit(0);
